package com.banking.secure;

import android.content.Context;
import android.content.pm.PackageManager;
import android.os.Build;
import android.provider.Settings;

import java.io.BufferedReader;
import java.io.File;
import java.io.InputStreamReader;

public class DeviceSecurityChecker {

    public static class SecurityCheckResult {
        private final boolean isSecure;
        private final String reason;

        public SecurityCheckResult(boolean isSecure, String reason) {
            this.isSecure = isSecure;
            this.reason = reason;
        }

        public boolean isSecure() { return isSecure; }
        public String getReason() { return reason; }
    }

    public static SecurityCheckResult performSecurityCheck(Context context) {
        if (isDeviceRooted()) {
            return new SecurityCheckResult(false, "Device appears to be rooted. Banking operations are not permitted on rooted devices.");
        }

        if (isEmulator()) {
            return new SecurityCheckResult(false, "Running on an emulator is not permitted for banking operations.");
        }

        if (isDebuggerAttached()) {
            return new SecurityCheckResult(false, "Debugger detected. Banking operations are suspended.");
        }

        if (isDeveloperOptionsEnabled(context)) {
            return new SecurityCheckResult(false, "Developer options are enabled. Please disable them for secure banking.");
        }

        if (isAdbEnabled(context)) {
            return new SecurityCheckResult(false, "USB debugging is enabled. Please disable it for secure banking.");
        }

        return new SecurityCheckResult(true, "Device security checks passed.");
    }

    private static boolean isDeviceRooted() {
        // Check for su binary
        String[] paths = {
                "/system/app/Superuser.apk",
                "/sbin/su",
                "/system/bin/su",
                "/system/xbin/su",
                "/data/local/xbin/su",
                "/data/local/bin/su",
                "/system/sd/xbin/su",
                "/system/bin/failsafe/su",
                "/data/local/su",
                "/su/bin/su"
        };

        for (String path : paths) {
            if (new File(path).exists()) {
                return true;
            }
        }

        // Check for root management apps
        String[] rootPackages = {
                "com.topjohnwu.magisk",
                "eu.chainfire.supersu",
                "com.koushikdutta.superuser",
                "com.noshufou.android.su"
        };

        try {
            Process process = Runtime.getRuntime().exec(new String[]{"which", "su"});
            BufferedReader reader = new BufferedReader(new InputStreamReader(process.getInputStream()));
            if (reader.readLine() != null) {
                reader.close();
                return true;
            }
            reader.close();
        } catch (Exception ignored) {
        }

        // Check build tags
        String buildTags = Build.TAGS;
        if (buildTags != null && buildTags.contains("test-keys")) {
            return true;
        }

        return false;
    }

    private static boolean isEmulator() {
        return Build.FINGERPRINT.startsWith("generic")
                || Build.FINGERPRINT.startsWith("unknown")
                || Build.MODEL.contains("google_sdk")
                || Build.MODEL.contains("Emulator")
                || Build.MODEL.contains("Android SDK built for x86")
                || Build.MANUFACTURER.contains("Genymotion")
                || (Build.BRAND.startsWith("generic") && Build.DEVICE.startsWith("generic"))
                || "google_sdk".equals(Build.PRODUCT)
                || Build.HARDWARE.contains("goldfish")
                || Build.HARDWARE.contains("ranchu");
    }

    private static boolean isDebuggerAttached() {
        return android.os.Debug.isDebuggerConnected() || android.os.Debug.waitingForDebugger();
    }

    private static boolean isDeveloperOptionsEnabled(Context context) {
        try {
            return Settings.Secure.getInt(context.getContentResolver(),
                    Settings.Global.DEVELOPMENT_SETTINGS_ENABLED, 0) != 0;
        } catch (Exception e) {
            return false;
        }
    }

    private static boolean isAdbEnabled(Context context) {
        try {
            return Settings.Global.getInt(context.getContentResolver(),
                    Settings.Global.ADB_ENABLED, 0) != 0;
        } catch (Exception e) {
            return false;
        }
    }
}

