package com.banking.secure;

import android.content.Context;
import android.content.SharedPreferences;

import java.util.concurrent.TimeUnit;

public class SessionManager {

    private static final long SESSION_TIMEOUT_MS = TimeUnit.MINUTES.toMillis(5);
    private static final long ABSOLUTE_TIMEOUT_MS = TimeUnit.MINUTES.toMillis(30);
    private static final String KEY_SESSION_TOKEN = "session_token";
    private static final String KEY_SESSION_START = "session_start";
    private static final String KEY_LAST_ACTIVITY = "last_activity";
    private static final String KEY_USER_ID = "user_id";

    private final SecurityManager securityManager;
    private SharedPreferences encryptedPrefs;

    public SessionManager(Context context) throws Exception {
        this.securityManager = new SecurityManager(context);
        this.encryptedPrefs = securityManager.getEncryptedPreferences();
    }

    public void createSession(String userId, String authToken) {
        long now = System.currentTimeMillis();
        encryptedPrefs.edit()
                .putString(KEY_SESSION_TOKEN, authToken)
                .putString(KEY_USER_ID, userId)
                .putLong(KEY_SESSION_START, now)
                .putLong(KEY_LAST_ACTIVITY, now)
                .apply();
    }

    public boolean isSessionValid() {
        String token = encryptedPrefs.getString(KEY_SESSION_TOKEN, null);
        if (token == null) return false;

        long now = System.currentTimeMillis();
        long sessionStart = encryptedPrefs.getLong(KEY_SESSION_START, 0);
        long lastActivity = encryptedPrefs.getLong(KEY_LAST_ACTIVITY, 0);

        // Check idle timeout
        if (now - lastActivity > SESSION_TIMEOUT_MS) {
            destroySession();
            return false;
        }

        // Check absolute timeout
        if (now - sessionStart > ABSOLUTE_TIMEOUT_MS) {
            destroySession();
            return false;
        }

        return true;
    }

    public void refreshActivity() {
        if (isSessionValid()) {
            encryptedPrefs.edit()
                    .putLong(KEY_LAST_ACTIVITY, System.currentTimeMillis())
                    .apply();
        }
    }

    public String getSessionToken() {
        if (isSessionValid()) {
            return encryptedPrefs.getString(KEY_SESSION_TOKEN, null);
        }
        return null;
    }

    public String getUserId() {
        if (isSessionValid()) {
            return encryptedPrefs.getString(KEY_USER_ID, null);
        }
        return null;
    }

    public void destroySession() {
        encryptedPrefs.edit()
                .remove(KEY_SESSION_TOKEN)
                .remove(KEY_USER_ID)
                .remove(KEY_SESSION_START)
                .remove(KEY_LAST_ACTIVITY)
                .apply();
    }

    public long getRemainingIdleTime() {
        long lastActivity = encryptedPrefs.getLong(KEY_LAST_ACTIVITY, 0);
        long elapsed = System.currentTimeMillis() - lastActivity;
        return Math.max(0, SESSION_TIMEOUT_MS - elapsed);
    }
}

